import { Component, AfterViewInit, ElementRef, ViewChild } from '@angular/core';
import { NetworkAnimationService } from '../../services/network-animation.service';

@Component({
  selector: 'app-network-animation',
  templateUrl: './network-animation.component.html',
  styleUrls: ['./network-animation.component.scss'],
})
export class NetworkAnimationComponent implements AfterViewInit {
  @ViewChild('canvas') canvasRef!: ElementRef<HTMLCanvasElement>;

  constructor(private networkAnimationService: NetworkAnimationService) {}

  ngAfterViewInit() {
    this.networkAnimationService.initAnimation(this.canvasRef.nativeElement);
  }
}
