import { Component, inject, OnInit } from '@angular/core';
import {
  NonNullableFormBuilder,
  ReactiveFormsModule,
  Validators,
} from '@angular/forms';
import { Router, RouterModule } from '@angular/router';
import { NgIf } from '@angular/common';

import { FloatLabel } from 'primeng/floatlabel';
import { ButtonModule } from 'primeng/button';
import { PasswordModule } from 'primeng/password';
import { InputTextModule } from 'primeng/inputtext';
import { SelectChangeEvent, SelectModule } from 'primeng/select';

import { AuthService } from '../../../../core/services/auth.service';
import { AuthTokenManagerService } from '../../../../core/services/auth-token-manager.service';
import { environment } from '../../../../../environments/environment';
import { ApiUrlService } from '../../../../core/services/api-url.service';

@Component({
  selector: 'app-login',
  imports: [
    RouterModule,
    ReactiveFormsModule,
    NgIf,
    FloatLabel,
    ButtonModule,
    PasswordModule,
    InputTextModule,
    SelectModule,
  ],
  templateUrl: './login.component.html',
  styleUrl: './login.component.scss',
})
export class LoginComponent implements OnInit {
  private readonly apiUrlService = inject(ApiUrlService);
  private readonly authService = inject(AuthService);
  private readonly authTokenManagerService = inject(AuthTokenManagerService);
  private readonly router = inject(Router);
  private readonly fb = inject(NonNullableFormBuilder);
  
  readonly environment = environment;
  readonly apiOptions = [
    ...environment.apiUrls.map((url) => ({
      label: url,
      value: url,
    })),
  ];

  loginForm = this.fb.group({
    username: this.fb.control('', Validators.required),
    password: this.fb.control('', Validators.required),
    apiUrl: this.fb.control('', Validators.required), // Initialize empty or with a placeholder
  });

  currentYear: number = new Date().getFullYear();
  loading = false;

  ngOnInit(): void {
    this.initializeApiUrl();
  }

  private initializeApiUrl(): void {
    // If API dropdown is not shown, use the first API URL without showing the dropdown
    if (!environment.showApiDropdown) {
      const firstApiUrl = environment.apiUrls[0];
      if (firstApiUrl) {
        this.apiUrlService.setApiUrl(firstApiUrl);
      }
      return;
    }
    
    // Only when API dropdown is enabled, initialize it
    const currentUrl = this.apiUrlService.getCurrentApiUrl();
    const firstOptionUrl = this.apiOptions[0]?.value;

    if (!firstOptionUrl) {
      this.loginForm.controls.apiUrl.disable();
      return;
    }

    const isValidOption = this.apiOptions.some(
      (option) => option.value === currentUrl,
    );

    let initialApiUrl: string;
    if (isValidOption) {
      initialApiUrl = currentUrl;
    } else {
      initialApiUrl = firstOptionUrl;
      this.apiUrlService.setApiUrl(initialApiUrl);
    }

    this.loginForm.controls.apiUrl.setValue(initialApiUrl);
  }

  onSubmit() {
    if (this.loginForm.valid) {
      this.loading = true;
      const { username, password } = this.loginForm.getRawValue();

      this.authService.login(username, password).subscribe({
        next: (result) => {
          this.loading = false;
          this.authTokenManagerService.storeTokens(result);
          this.router.navigate(['/']).catch((err) => {
            console.error('Navigation failed after login:', err); // Log navigation error
          });
        },
        error: () => {
          this.loading = false;
          this.loginForm.controls.password.reset();
        },
      });
    }
  }

  onApiUrlChange(event: SelectChangeEvent) {
    this.apiUrlService.setApiUrl(event.value);
  }
}
